## 3. 데이터 수집 구현

### 3.1 ESCO Client 구현

```typescript
// src/services/esco/escoClient.ts

import axios, { AxiosInstance, AxiosRequestConfig } from 'axios';
import { ESCOSkill } from './types';

export class ESCOClient {
  private client: AxiosInstance;
  private baseURL: string;
  private version: string;

  constructor(baseURL?: string, version: string = 'v1.2') {
    this.baseURL = baseURL || 'https://ec.europa.eu/esco/api';
    this.version = version;

    this.client = axios.create({
      baseURL: this.baseURL,
      timeout: 30000,
      headers: {
        'Accept': 'application/json',
        'User-Agent': 'ESCO-Skills-Ontology/1.0'
      }
    });

    // 재시도 로직
    this.setupRetry();
  }

  private setupRetry() {
    this.client.interceptors.response.use(
      response => response,
      async error => {
        const config = error.config as AxiosRequestConfig & { _retry?: number };

        if (!config._retry) {
          config._retry = 0;
        }

        if (config._retry < 3) {
          config._retry += 1;

          // Exponential backoff
          const delay = Math.pow(2, config._retry) * 1000;
          await new Promise(resolve => setTimeout(resolve, delay));

          return this.client(config);
        }

        return Promise.reject(error);
      }
    );
  }

  /**
   * 특정 스킬 URI로 스킬 정보 조회
   */
  async getSkillByURI(uri: string, language: string = 'en'): Promise<ESCOSkill> {
    try {
      const response = await this.client.get('/resource/skill', {
        params: {
          uri,
          language,
          selectedVersion: this.version
        }
      });

      return this.transformSkillData(response.data);
    } catch (error) {
      console.error(`Failed to fetch skill: ${uri}`, error);
      throw new Error(`ESCO API Error: ${error.message}`);
    }
  }

  /**
   * 여러 스킬을 배치로 조회
   */
  async getSkillsBatch(uris: string[], language: string = 'en'): Promise<ESCOSkill[]> {
    const promises = uris.map(uri => this.getSkillByURI(uri, language));

    // Promise.allSettled를 사용하여 실패한 것도 처리
    const results = await Promise.allSettled(promises);

    return results
      .filter(result => result.status === 'fulfilled')
      .map(result => (result as PromiseFulfilledResult<ESCOSkill>).value);
  }

  /**
   * 스킬 검색 (자동완성)
   */
  async suggestSkills(text: string, language: string = 'en', limit: number = 10) {
    try {
      const response = await this.client.get('/suggest', {
        params: {
          text,
          language,
          type: 'skill',
          limit,
          selectedVersion: this.version
        }
      });

      return response.data.results || [];
    } catch (error) {
      console.error('Failed to suggest skills:', error);
      return [];
    }
  }

  /**
   * 데이터 변환 (ESCO 응답 → 내부 형식)
   */
  private transformSkillData(data: any): ESCOSkill {
    return {
      uri: data._about || data.uri,
      conceptType: data.conceptType || 'skill',
      preferredLabel: data.preferredLabel || {},
      altLabels: data.altLabels || {},
      description: data.description || {},
      skillType: data.skillType?._about,
      reuseLevel: data.skillReuseLevel?._about,
      broaderConcept: this.extractURIs(data.broaderConcept),
      narrowerConcept: this.extractURIs(data.narrowerConcept),
      relatedConcept: this.extractURIs(data.relatedConcept),
      modifiedDate: data.modifiedDate,
      status: data.status
    };
  }

  private extractURIs(concepts: any): string[] {
    if (!concepts) return [];
    if (Array.isArray(concepts)) {
      return concepts.map(c => c._about || c);
    }
    return [concepts._about || concepts];
  }
}

// Export singleton instance
export const escoClient = new ESCOClient();
```

### 3.2 디지털 스킬 수집 스크립트

```typescript
// src/scripts/fetchDigitalSkills.ts

import { ESCOClient } from '../services/esco/escoClient';
import { SkillsRepository } from '../services/database/skillsRepository';
import * as fs from 'fs';
import * as path from 'path';

/**
 * ESCO의 1,201개 디지털 스킬을 수집하는 스크립트
 */
class DigitalSkillsFetcher {
  private escoClient: ESCOClient;
  private skillsRepo: SkillsRepository;
  private digitalSkillsFile: string;

  constructor() {
    this.escoClient = new ESCOClient();
    this.skillsRepo = new SkillsRepository();
    this.digitalSkillsFile = path.join(__dirname, '../../data/digitalSkillsCollection.csv');
  }

  /**
   * Step 1: CSV 파일에서 디지털 스킬 URI 목록 로드
   */
  async loadDigitalSkillURIs(): Promise<string[]> {
    console.log('Loading digital skills URIs from CSV...');

    // ESCO에서 다운로드한 digitalSkillsCollection.csv 파일 읽기
    const csvContent = fs.readFileSync(this.digitalSkillsFile, 'utf-8');
    const lines = csvContent.split('\n');

    // Header 제외하고 URI 추출
    const uris = lines
      .slice(1)
      .map(line => {
        const columns = line.split(',');
        return columns[0]?.trim(); // conceptUri
      })
      .filter(uri => uri && uri.startsWith('http://data.europa.eu/esco/skill/'));

    console.log(`Found ${uris.length} digital skills URIs`);
    return uris;
  }

  /**
   * Step 2: 각 URI에 대해 상세 정보 가져오기
   */
  async fetchAllDigitalSkills(uris: string[]): Promise<void> {
    console.log('Fetching detailed information for each skill...');

    const batchSize = 50;
    let processed = 0;
    let failed = 0;

    for (let i = 0; i < uris.length; i += batchSize) {
      const batch = uris.slice(i, i + batchSize);

      console.log(`Processing batch ${Math.floor(i / batchSize) + 1}/${Math.ceil(uris.length / batchSize)}`);

      try {
        // 영어와 한국어 모두 수집
        const skillsEN = await this.escoClient.getSkillsBatch(batch, 'en');
        const skillsKO = await this.escoClient.getSkillsBatch(batch, 'ko');

        // 데이터베이스에 저장
        for (const skillEN of skillsEN) {
          try {
            const skillKO = skillsKO.find(s => s.uri === skillEN.uri);

            await this.skillsRepo.upsertSkill({
              esco_uri: skillEN.uri,
              preferred_label_en: skillEN.preferredLabel.en || skillEN.preferredLabel.eng,
              preferred_label_ko: skillKO?.preferredLabel.ko || null,
              description_en: skillEN.description?.en?.literal || null,
              description_ko: skillKO?.description?.ko?.literal || null,
              skill_type: this.extractSkillType(skillEN.skillType),
              is_digital_skill: true,
              reusability_level: this.extractReusabilityLevel(skillEN.reuseLevel)
            });

            processed++;
          } catch (error) {
            console.error(`Failed to save skill ${skillEN.uri}:`, error);
            failed++;
          }
        }

        // Rate limiting: API 부하 방지를 위해 대기
        await this.sleep(2000);

      } catch (error) {
        console.error(`Batch processing failed:`, error);
        failed += batch.length;
      }

      console.log(`Progress: ${processed} processed, ${failed} failed`);
    }

    console.log(`\nCompleted: ${processed} skills saved, ${failed} failed`);
  }

  /**
   * Step 3: 스킬 간 관계 수집
   */
  async fetchSkillRelationships(): Promise<void> {
    console.log('Fetching skill relationships...');

    const skills = await this.skillsRepo.getAllSkills();

    for (const skill of skills) {
      try {
        const skillData = await this.escoClient.getSkillByURI(skill.esco_uri, 'en');

        // Broader skills (상위 스킬)
        for (const broaderUri of skillData.broaderConcept || []) {
          await this.skillsRepo.upsertRelationship({
            source_skill_id: skill.id,
            target_skill_uri: broaderUri,
            relationship_type: 'broader',
            strength: 1.0
          });
        }

        // Related skills (관련 스킬)
        for (const relatedUri of skillData.relatedConcept || []) {
          await this.skillsRepo.upsertRelationship({
            source_skill_id: skill.id,
            target_skill_uri: relatedUri,
            relationship_type: 'related',
            strength: 0.7
          });
        }

      } catch (error) {
        console.error(`Failed to fetch relationships for ${skill.esco_uri}:`, error);
      }

      // Rate limiting
      await this.sleep(500);
    }

    console.log('Relationships fetching completed');
  }

  /**
   * Helper: 스킬 타입 추출
   */
  private extractSkillType(skillTypeUri?: string): string {
    if (!skillTypeUri) return 'skill';

    if (skillTypeUri.includes('knowledge')) return 'knowledge';
    if (skillTypeUri.includes('skill')) return 'skill';
    if (skillTypeUri.includes('competence')) return 'competence';

    return 'skill';
  }

  /**
   * Helper: Reusability Level 추출
   */
  private extractReusabilityLevel(reuseUri?: string): string {
    if (!reuseUri) return 'unknown';

    if (reuseUri.includes('transversal')) return 'transversal';
    if (reuseUri.includes('cross-sectoral')) return 'cross-sectoral';
    if (reuseUri.includes('sector-specific')) return 'sector-specific';
    if (reuseUri.includes('occupation-specific')) return 'occupation-specific';

    return 'unknown';
  }

  /**
   * Helper: Sleep
   */
  private sleep(ms: number): Promise<void> {
    return new Promise(resolve => setTimeout(resolve, ms));
  }

  /**
   * 전체 실행
   */
  async run(): Promise<void> {
    try {
      console.log('=== ESCO Digital Skills Fetcher ===\n');

      // Step 1: URI 목록 로드
      const uris = await this.loadDigitalSkillURIs();

      // Step 2: 스킬 상세 정보 수집
      await this.fetchAllDigitalSkills(uris);

      // Step 3: 관계 정보 수집
      await this.fetchSkillRelationships();

      console.log('\n=== Fetching completed successfully ===');

    } catch (error) {
      console.error('Fatal error:', error);
      process.exit(1);
    }
  }
}

// 실행
if (require.main === module) {
  const fetcher = new DigitalSkillsFetcher();
  fetcher.run()
    .then(() => process.exit(0))
    .catch(error => {
      console.error(error);
      process.exit(1);
    });
}

export default DigitalSkillsFetcher;
```

