## 4. 데이터베이스 설계

### 4.1 스키마 정의

```sql
-- scripts/init.sql

-- Extensions
CREATE EXTENSION IF NOT EXISTS "uuid-ossp";
CREATE EXTENSION IF NOT EXISTS "pg_trgm"; -- 유사도 검색용

-- Skills 테이블
CREATE TABLE skills (
    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    esco_uri VARCHAR(255) UNIQUE NOT NULL,
    preferred_label_en VARCHAR(500),
    preferred_label_ko VARCHAR(500),
    alt_labels_en TEXT[], -- 대체 레이블 (배열)
    alt_labels_ko TEXT[],
    description_en TEXT,
    description_ko TEXT,
    skill_type VARCHAR(50) CHECK (skill_type IN ('knowledge', 'skill', 'competence')),
    is_digital_skill BOOLEAN DEFAULT FALSE,
    reusability_level VARCHAR(50),
    created_at TIMESTAMP DEFAULT NOW(),
    updated_at TIMESTAMP DEFAULT NOW()
);

-- 인덱스
CREATE INDEX idx_skills_digital ON skills(is_digital_skill) WHERE is_digital_skill = TRUE;
CREATE INDEX idx_skills_type ON skills(skill_type);
CREATE INDEX idx_skills_reusability ON skills(reusability_level);
CREATE INDEX idx_skills_label_en_trgm ON skills USING gin(preferred_label_en gin_trgm_ops);
CREATE INDEX idx_skills_label_ko_trgm ON skills USING gin(preferred_label_ko gin_trgm_ops);

-- Skill Mappings 테이블 (DX/AX 레벨 매핑)
CREATE TABLE skill_mappings (
    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    skill_id UUID REFERENCES skills(id) ON DELETE CASCADE,
    dx_level VARCHAR(20) CHECK (dx_level IN ('starter', 'enabler', 'cds')),
    ax_level VARCHAR(20) CHECK (ax_level IN ('lv1', 'lv2', 'lv3')),
    custom_category VARCHAR(100),
    importance_score INT CHECK (importance_score BETWEEN 1 AND 10),
    difficulty_score INT CHECK (difficulty_score BETWEEN 1 AND 10),
    created_by UUID,
    approved_by UUID,
    approved_at TIMESTAMP,
    created_at TIMESTAMP DEFAULT NOW(),
    updated_at TIMESTAMP DEFAULT NOW(),
    UNIQUE(skill_id, dx_level),
    UNIQUE(skill_id, ax_level)
);

CREATE INDEX idx_mappings_dx_level ON skill_mappings(dx_level);
CREATE INDEX idx_mappings_ax_level ON skill_mappings(ax_level);

-- Skill Relationships 테이블
CREATE TABLE skill_relationships (
    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    source_skill_id UUID REFERENCES skills(id) ON DELETE CASCADE,
    target_skill_id UUID REFERENCES skills(id) ON DELETE CASCADE,
    relationship_type VARCHAR(50) CHECK (relationship_type IN 
        ('prerequisite', 'related', 'broader', 'narrower', 'essential', 'optional')),
    strength DECIMAL(3,2) CHECK (strength BETWEEN 0.00 AND 1.00),
    created_at TIMESTAMP DEFAULT NOW(),
    UNIQUE(source_skill_id, target_skill_id, relationship_type)
);

CREATE INDEX idx_relationships_source ON skill_relationships(source_skill_id);
CREATE INDEX idx_relationships_target ON skill_relationships(target_skill_id);
CREATE INDEX idx_relationships_type ON skill_relationships(relationship_type);

-- User Skills 테이블
CREATE TABLE user_skills (
    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    user_id VARCHAR(100) NOT NULL,
    skill_id UUID REFERENCES skills(id) ON DELETE CASCADE,
    proficiency_level INT CHECK (proficiency_level BETWEEN 1 AND 5),
    acquired_date DATE,
    evidence_type VARCHAR(50) CHECK (evidence_type IN 
        ('course', 'project', 'certification', 'assessment', 'self-reported')),
    evidence_uri VARCHAR(500),
    verified BOOLEAN DEFAULT FALSE,
    verified_by UUID,
    verified_at TIMESTAMP,
    created_at TIMESTAMP DEFAULT NOW(),
    updated_at TIMESTAMP DEFAULT NOW(),
    UNIQUE(user_id, skill_id)
);

CREATE INDEX idx_user_skills_user ON user_skills(user_id);
CREATE INDEX idx_user_skills_skill ON user_skills(skill_id);
CREATE INDEX idx_user_skills_proficiency ON user_skills(proficiency_level);

-- Skill Recommendations 테이블
CREATE TABLE skill_recommendations (
    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    user_id VARCHAR(100) NOT NULL,
    skill_id UUID REFERENCES skills(id) ON DELETE CASCADE,
    recommendation_reason TEXT,
    priority_score INT CHECK (priority_score BETWEEN 1 AND 100),
    status VARCHAR(20) CHECK (status IN ('pending', 'accepted', 'rejected', 'completed')),
    created_at TIMESTAMP DEFAULT NOW(),
    updated_at TIMESTAMP DEFAULT NOW(),
    expires_at TIMESTAMP
);

CREATE INDEX idx_recommendations_user ON skill_recommendations(user_id);
CREATE INDEX idx_recommendations_status ON skill_recommendations(status);

-- Audit Log 테이블
CREATE TABLE audit_logs (
    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    entity_type VARCHAR(50) NOT NULL,
    entity_id UUID NOT NULL,
    action VARCHAR(20) CHECK (action IN ('create', 'update', 'delete')),
    user_id VARCHAR(100) NOT NULL,
    changes JSONB,
    created_at TIMESTAMP DEFAULT NOW()
);

CREATE INDEX idx_audit_entity ON audit_logs(entity_type, entity_id);
CREATE INDEX idx_audit_user ON audit_logs(user_id);
CREATE INDEX idx_audit_created ON audit_logs(created_at DESC);

-- Functions: Update timestamp
CREATE OR REPLACE FUNCTION update_updated_at_column()
RETURNS TRIGGER AS $$
BEGIN
    NEW.updated_at = NOW();
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

-- Triggers
CREATE TRIGGER update_skills_updated_at BEFORE UPDATE ON skills
    FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();

CREATE TRIGGER update_mappings_updated_at BEFORE UPDATE ON skill_mappings
    FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();

CREATE TRIGGER update_user_skills_updated_at BEFORE UPDATE ON user_skills
    FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();

-- Views: 자주 사용하는 쿼리

-- View: Digital Skills with Mappings
CREATE VIEW v_digital_skills_with_mappings AS
SELECT 
    s.*,
    m.dx_level,
    m.ax_level,
    m.custom_category,
    m.importance_score,
    m.difficulty_score
FROM skills s
LEFT JOIN skill_mappings m ON s.id = m.skill_id
WHERE s.is_digital_skill = TRUE;

-- View: Skill Hierarchy
CREATE VIEW v_skill_hierarchy AS
WITH RECURSIVE skill_tree AS (
    -- Base case: 최상위 스킬
    SELECT 
        s.id,
        s.esco_uri,
        s.preferred_label_en,
        s.preferred_label_ko,
        ARRAY[s.id] as path,
        0 as level
    FROM skills s
    WHERE NOT EXISTS (
        SELECT 1 FROM skill_relationships sr
        WHERE sr.target_skill_id = s.id
        AND sr.relationship_type = 'broader'
    )

    UNION ALL

    -- Recursive case: 하위 스킬
    SELECT 
        s.id,
        s.esco_uri,
        s.preferred_label_en,
        s.preferred_label_ko,
        st.path || s.id,
        st.level + 1
    FROM skills s
    INNER JOIN skill_relationships sr ON s.id = sr.target_skill_id
    INNER JOIN skill_tree st ON sr.source_skill_id = st.id
    WHERE sr.relationship_type = 'narrower'
    AND NOT s.id = ANY(st.path) -- 순환 방지
)
SELECT * FROM skill_tree;

