### 4.2 Database Repository 구현

```typescript
// src/services/database/skillsRepository.ts

import { Pool, QueryResult } from 'pg';
import { DatabaseConfig } from '../../config/database';

export interface SkillData {
  id?: string;
  esco_uri: string;
  preferred_label_en?: string;
  preferred_label_ko?: string;
  description_en?: string;
  description_ko?: string;
  skill_type?: string;
  is_digital_skill?: boolean;
  reusability_level?: string;
}

export class SkillsRepository {
  private pool: Pool;

  constructor() {
    this.pool = DatabaseConfig.getPool();
  }

  /**
   * 스킬 생성/업데이트 (Upsert)
   */
  async upsertSkill(skillData: SkillData): Promise<string> {
    const query = `
      INSERT INTO skills (
        esco_uri, preferred_label_en, preferred_label_ko,
        description_en, description_ko, skill_type,
        is_digital_skill, reusability_level
      ) VALUES ($1, $2, $3, $4, $5, $6, $7, $8)
      ON CONFLICT (esco_uri) DO UPDATE SET
        preferred_label_en = EXCLUDED.preferred_label_en,
        preferred_label_ko = EXCLUDED.preferred_label_ko,
        description_en = EXCLUDED.description_en,
        description_ko = EXCLUDED.description_ko,
        skill_type = EXCLUDED.skill_type,
        is_digital_skill = EXCLUDED.is_digital_skill,
        reusability_level = EXCLUDED.reusability_level,
        updated_at = NOW()
      RETURNING id
    `;

    const values = [
      skillData.esco_uri,
      skillData.preferred_label_en,
      skillData.preferred_label_ko,
      skillData.description_en,
      skillData.description_ko,
      skillData.skill_type,
      skillData.is_digital_skill,
      skillData.reusability_level
    ];

    try {
      const result = await this.pool.query(query, values);
      return result.rows[0].id;
    } catch (error) {
      console.error('Error upserting skill:', error);
      throw error;
    }
  }

  /**
   * URI로 스킬 조회
   */
  async getSkillByURI(uri: string): Promise<any> {
    const query = 'SELECT * FROM skills WHERE esco_uri = $1';
    const result = await this.pool.query(query, [uri]);
    return result.rows[0];
  }

  /**
   * ID로 스킬 조회
   */
  async getSkillById(id: string): Promise<any> {
    const query = 'SELECT * FROM skills WHERE id = $1';
    const result = await this.pool.query(query, [id]);
    return result.rows[0];
  }

  /**
   * 모든 스킬 조회 (페이지네이션)
   */
  async getAllSkills(offset: number = 0, limit: number = 100): Promise<any[]> {
    const query = `
      SELECT * FROM skills
      ORDER BY preferred_label_en
      LIMIT $1 OFFSET $2
    `;
    const result = await this.pool.query(query, [limit, offset]);
    return result.rows;
  }

  /**
   * 디지털 스킬만 조회
   */
  async getDigitalSkills(offset: number = 0, limit: number = 100): Promise<any[]> {
    const query = `
      SELECT * FROM skills
      WHERE is_digital_skill = TRUE
      ORDER BY preferred_label_en
      LIMIT $1 OFFSET $2
    `;
    const result = await this.pool.query(query, [limit, offset]);
    return result.rows;
  }

  /**
   * 스킬 검색 (Full-text search)
   */
  async searchSkills(
    searchTerm: string,
    language: 'en' | 'ko' = 'en',
    filters?: {
      skillType?: string;
      isDigital?: boolean;
      reusabilityLevel?: string;
    },
    offset: number = 0,
    limit: number = 20
  ): Promise<{ skills: any[]; total: number }> {
    const labelColumn = language === 'ko' ? 'preferred_label_ko' : 'preferred_label_en';
    const descColumn = language === 'ko' ? 'description_ko' : 'description_en';

    let whereConditions = [`${labelColumn} ILIKE $1 OR ${descColumn} ILIKE $1`];
    let params: any[] = [`%${searchTerm}%`];
    let paramIndex = 2;

    if (filters?.skillType) {
      whereConditions.push(`skill_type = $${paramIndex}`);
      params.push(filters.skillType);
      paramIndex++;
    }

    if (filters?.isDigital !== undefined) {
      whereConditions.push(`is_digital_skill = $${paramIndex}`);
      params.push(filters.isDigital);
      paramIndex++;
    }

    if (filters?.reusabilityLevel) {
      whereConditions.push(`reusability_level = $${paramIndex}`);
      params.push(filters.reusabilityLevel);
      paramIndex++;
    }

    const whereClause = whereConditions.join(' AND ');

    // Count query
    const countQuery = `SELECT COUNT(*) FROM skills WHERE ${whereClause}`;
    const countResult = await this.pool.query(countQuery, params);
    const total = parseInt(countResult.rows[0].count);

    // Data query with similarity ranking
    const dataQuery = `
      SELECT *,
        similarity(${labelColumn}, $1) as similarity_score
      FROM skills
      WHERE ${whereClause}
      ORDER BY similarity_score DESC, ${labelColumn}
      LIMIT $${paramIndex} OFFSET $${paramIndex + 1}
    `;
    params.push(limit, offset);

    const dataResult = await this.pool.query(dataQuery, params);

    return {
      skills: dataResult.rows,
      total
    };
  }

  /**
   * 스킬 관계 저장
   */
  async upsertRelationship(relationData: {
    source_skill_id: string;
    target_skill_uri: string;
    relationship_type: string;
    strength: number;
  }): Promise<void> {
    // 먼저 target URI로 skill ID 찾기
    const targetSkill = await this.getSkillByURI(relationData.target_skill_uri);

    if (!targetSkill) {
      console.warn(`Target skill not found: ${relationData.target_skill_uri}`);
      return;
    }

    const query = `
      INSERT INTO skill_relationships (
        source_skill_id, target_skill_id, relationship_type, strength
      ) VALUES ($1, $2, $3, $4)
      ON CONFLICT (source_skill_id, target_skill_id, relationship_type) DO UPDATE SET
        strength = EXCLUDED.strength
    `;

    await this.pool.query(query, [
      relationData.source_skill_id,
      targetSkill.id,
      relationData.relationship_type,
      relationData.strength
    ]);
  }

  /**
   * 스킬의 관련 스킬 조회
   */
  async getRelatedSkills(
    skillId: string,
    relationshipType?: string
  ): Promise<any[]> {
    let query = `
      SELECT s.*, sr.relationship_type, sr.strength
      FROM skills s
      INNER JOIN skill_relationships sr ON s.id = sr.target_skill_id
      WHERE sr.source_skill_id = $1
    `;

    const params: any[] = [skillId];

    if (relationshipType) {
      query += ` AND sr.relationship_type = $2`;
      params.push(relationshipType);
    }

    query += ` ORDER BY sr.strength DESC, s.preferred_label_en`;

    const result = await this.pool.query(query, params);
    return result.rows;
  }

  /**
   * 통계 조회
   */
  async getStats(): Promise<{
    totalSkills: number;
    digitalSkills: number;
    byType: { [key: string]: number };
    byReusability: { [key: string]: number };
  }> {
    const queries = {
      total: 'SELECT COUNT(*) as count FROM skills',
      digital: 'SELECT COUNT(*) as count FROM skills WHERE is_digital_skill = TRUE',
      byType: `
        SELECT skill_type, COUNT(*) as count 
        FROM skills 
        GROUP BY skill_type
      `,
      byReusability: `
        SELECT reusability_level, COUNT(*) as count 
        FROM skills 
        GROUP BY reusability_level
      `
    };

    const [total, digital, byType, byReusability] = await Promise.all([
      this.pool.query(queries.total),
      this.pool.query(queries.digital),
      this.pool.query(queries.byType),
      this.pool.query(queries.byReusability)
    ]);

    return {
      totalSkills: parseInt(total.rows[0].count),
      digitalSkills: parseInt(digital.rows[0].count),
      byType: byType.rows.reduce((acc, row) => {
        acc[row.skill_type] = parseInt(row.count);
        return acc;
      }, {}),
      byReusability: byReusability.rows.reduce((acc, row) => {
        acc[row.reusability_level] = parseInt(row.count);
        return acc;
      }, {})
    };
  }

  /**
   * Connection cleanup
   */
  async close(): Promise<void> {
    await this.pool.end();
  }
}
