const router = Router();
const skillsRepo = new SkillsRepository();

/**
 * GET /skills
 * 스킬 목록 조회 (페이지네이션)
 */
router.get('/', async (req: Request, res: Response, next: NextFunction) => {
  try {
    const page = parseInt(req.query.page as string) || 1;
    const limit = parseInt(req.query.limit as string) || 20;
    const offset = (page - 1) * limit;

    const digitalOnly = req.query.digital === 'true';

    const skills = digitalOnly
      ? await skillsRepo.getDigitalSkills(offset, limit)
      : await skillsRepo.getAllSkills(offset, limit);

    const stats = await skillsRepo.getStats();
    const total = digitalOnly ? stats.digitalSkills : stats.totalSkills;

    res.json({
      data: skills,
      pagination: {
        page,
        limit,
        total,
        totalPages: Math.ceil(total / limit)
      }
    });
  } catch (error) {
    next(error);
  }
});

/**
 * GET /skills/search
 * 스킬 검색
 */
router.get('/search', async (req: Request, res: Response, next: NextFunction) => {
  try {
    const searchTerm = req.query.q as string;
    const language = (req.query.lang as 'en' | 'ko') || 'en';
    const page = parseInt(req.query.page as string) || 1;
    const limit = parseInt(req.query.limit as string) || 20;
    const offset = (page - 1) * limit;

    if (!searchTerm) {
      return res.status(400).json({
        error: 'Bad Request',
        message: 'Search term (q) is required'
      });
    }

    // Filters
    const filters: any = {};
    if (req.query.skillType) filters.skillType = req.query.skillType;
    if (req.query.digital) filters.isDigital = req.query.digital === 'true';
    if (req.query.reusability) filters.reusabilityLevel = req.query.reusability;

    const { skills, total } = await skillsRepo.searchSkills(
      searchTerm,
      language,
      filters,
      offset,
      limit
    );

    res.json({
      data: skills,
      pagination: {
        page,
        limit,
        total,
        totalPages: Math.ceil(total / limit)
      }
    });
  } catch (error) {
    next(error);
  }
});

