### 6.1 Elasticsearch 연동 (선택적)

```typescript
// src/services/search/searchService.ts

import { Client } from '@elastic/elasticsearch';

export class SearchService {
  private client: Client;
  private indexName: string = 'skills';

  constructor() {
    this.client = new Client({
      node: process.env.ELASTICSEARCH_URL || 'http://localhost:9200'
    });

    this.initializeIndex();
  }

  /**
   * 인덱스 초기화
   */
  private async initializeIndex() {
    const exists = await this.client.indices.exists({ index: this.indexName });

    if (!exists) {
      await this.client.indices.create({
        index: this.indexName,
        body: {
          settings: {
            analysis: {
              analyzer: {
                skill_analyzer: {
                  type: 'custom',
                  tokenizer: 'standard',
                  filter: ['lowercase', 'snowball', 'ngram_filter']
                }
              },
              filter: {
                ngram_filter: {
                  type: 'ngram',
                  min_gram: 3,
                  max_gram: 10
                }
              }
            }
          },
          mappings: {
            properties: {
              esco_uri: { type: 'keyword' },
              preferred_label_en: {
                type: 'text',
                analyzer: 'skill_analyzer',
                fields: {
                  keyword: { type: 'keyword' }
                }
              },
              preferred_label_ko: {
                type: 'text',
                analyzer: 'standard',
                fields: {
                  keyword: { type: 'keyword' }
                }
              },
              description_en: { type: 'text' },
              description_ko: { type: 'text' },
              skill_type: { type: 'keyword' },
              is_digital_skill: { type: 'boolean' },
              reusability_level: { type: 'keyword' },
              tags: { type: 'keyword' }
            }
          }
        }
      });
    }
  }

  /**
   * 스킬 인덱싱
   */
  async indexSkill(skill: any): Promise<void> {
    await this.client.index({
      index: this.indexName,
      id: skill.id,
      body: skill
    });
  }

  /**
   * 대량 인덱싱
   */
  async bulkIndexSkills(skills: any[]): Promise<void> {
    const body = skills.flatMap(skill => [
      { index: { _index: this.indexName, _id: skill.id } },
      skill
    ]);

    await this.client.bulk({ body, refresh: true });
  }

  /**
   * 검색
   */
  async search(query: {
    text: string;
    language?: 'en' | 'ko';
    filters?: any;
    size?: number;
    from?: number;
  }): Promise<any> {
    const { text, language = 'en', filters = {}, size = 20, from = 0 } = query;

    const labelField = language === 'ko' ? 'preferred_label_ko' : 'preferred_label_en';
    const descField = language === 'ko' ? 'description_ko' : 'description_en';

    const must: any[] = [
      {
        multi_match: {
          query: text,
          fields: [
            `${labelField}^3`,
            `${labelField}.keyword^2`,
            descField
          ],
          fuzziness: 'AUTO'
        }
      }
    ];

    // Filters
    if (filters.isDigital !== undefined) {
      must.push({ term: { is_digital_skill: filters.isDigital } });
    }
    if (filters.skillType) {
      must.push({ term: { skill_type: filters.skillType } });
    }
    if (filters.reusabilityLevel) {
      must.push({ term: { reusability_level: filters.reusabilityLevel } });
    }

    const result = await this.client.search({
      index: this.indexName,
      body: {
        query: {
          bool: { must }
        },
        highlight: {
          fields: {
            [labelField]: {},
            [descField]: {}
          }
        },
        size,
        from
      }
    });

    return {
      hits: result.hits.hits.map(hit => ({
        ...hit._source,
        score: hit._score,
        highlights: hit.highlight
      })),
      total: result.hits.total
    };
  }

  /**
   * 자동완성 제안
   */
  async suggest(prefix: string, language: 'en' | 'ko' = 'en'): Promise<string[]> {
    const field = language === 'ko' ? 'preferred_label_ko' : 'preferred_label_en';

    const result = await this.client.search({
      index: this.indexName,
      body: {
        suggest: {
          skill_suggest: {
            prefix,
            completion: {
              field: `${field}.completion`,
              size: 10,
              skip_duplicates: true
            }
          }
        }
      }
    });

    return result.suggest.skill_suggest[0].options.map((opt: any) => opt.text);
  }
}
```

