```

### 2.2 ESCO 스킬 데이터 구조

```typescript
// src/services/esco/types.ts

interface ESCOSkill {
  // 기본 정보
  uri: string;                    // 고유 식별자
  conceptType: 'skill' | 'knowledge';
  preferredLabel: {
    [language: string]: string;   // 언어별 레이블
  };
  altLabels?: {
    [language: string]: string[];
  };
  hiddenLabels?: {
    [language: string]: string[];
  };

  // 설명
  description?: {
    [language: string]: {
      literal: string;
    };
  };

  // 분류
  skillType?: 'skill/competence' | 'knowledge';
  reuseLevel?: 'cross-sectoral' | 'sector-specific' | 'occupation-specific' | 'transversal';

  // 관계
  broaderConcept?: string[];      // 상위 스킬
  narrowerConcept?: string[];     // 하위 스킬
  relatedConcept?: string[];      // 관련 스킬

  // 메타데이터
  modifiedDate?: string;
  status?: string;
}

interface ESCODigitalSkill {
  uri: string;
  isDigitalSkill: boolean;
  digitalCompetenceArea?: string; // DigComp 영역
}

interface ESCOSkillRelation {
  sourceUri: string;
  targetUri: string;
  relationType: 'essential' | 'optional';
  occupationUri?: string;
}
