-- Functions: Update timestamp
CREATE OR REPLACE FUNCTION update_updated_at_column()
RETURNS TRIGGER AS $$
BEGIN
    NEW.updated_at = NOW();
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

-- Triggers
CREATE TRIGGER update_skills_updated_at BEFORE UPDATE ON skills
    FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();

CREATE TRIGGER update_mappings_updated_at BEFORE UPDATE ON skill_mappings
    FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();

CREATE TRIGGER update_user_skills_updated_at BEFORE UPDATE ON user_skills
    FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();

-- Views: 자주 사용하는 쿼리

-- View: Digital Skills with Mappings
CREATE VIEW v_digital_skills_with_mappings AS
SELECT 
    s.*,
    m.dx_level,
    m.ax_level,
    m.custom_category,
    m.importance_score,
    m.difficulty_score
FROM skills s
LEFT JOIN skill_mappings m ON s.id = m.skill_id
WHERE s.is_digital_skill = TRUE;

-- View: Skill Hierarchy
CREATE VIEW v_skill_hierarchy AS
WITH RECURSIVE skill_tree AS (
    -- Base case: 최상위 스킬
    SELECT 
        s.id,
        s.esco_uri,
        s.preferred_label_en,
        s.preferred_label_ko,
        ARRAY[s.id] as path,
        0 as level
    FROM skills s
    WHERE NOT EXISTS (
        SELECT 1 FROM skill_relationships sr
        WHERE sr.target_skill_id = s.id
        AND sr.relationship_type = 'broader'
    )

    UNION ALL

    -- Recursive case: 하위 스킬
    SELECT 
        s.id,
        s.esco_uri,
        s.preferred_label_en,
        s.preferred_label_ko,
        st.path || s.id,
        st.level + 1
    FROM skills s
    INNER JOIN skill_relationships sr ON s.id = sr.target_skill_id
    INNER JOIN skill_tree st ON sr.source_skill_id = st.id
    WHERE sr.relationship_type = 'narrower'
    AND NOT s.id = ANY(st.path) -- 순환 방지
)
SELECT * FROM skill_tree;

