      : await skillsRepo.getAllSkills(offset, limit);

    const stats = await skillsRepo.getStats();
    const total = digitalOnly ? stats.digitalSkills : stats.totalSkills;

    res.json({
      data: skills,
      pagination: {
        page,
        limit,
        total,
        totalPages: Math.ceil(total / limit)
      }
    });
  } catch (error) {
