### 7.1 DX/AX 레벨 자동 매핑

```typescript
// src/services/mapping/autoMapper.ts

import { SkillsRepository } from '../database/skillsRepository';
import { MappingRepository } from '../database/mappingRepository';

export interface MappingRule {
  condition: (skill: any) => boolean;
  dxLevel?: 'starter' | 'enabler' | 'cds';
  axLevel?: 'lv1' | 'lv2' | 'lv3';
  importanceScore: number;
  difficultyScore: number;
}

export class AutoMapper {
  private skillsRepo: SkillsRepository;
  private mappingRepo: MappingRepository;

  constructor() {
    this.skillsRepo = new SkillsRepository();
    this.mappingRepo = new MappingRepository();
  }

  /**
   * 매핑 규칙 정의
   */
  private getMappingRules(): MappingRule[] {
    return [
      // DX Starter (Level 1) 규칙
      {
        condition: (skill) => 
          skill.is_digital_skill &&
          (skill.reusability_level === 'transversal' ||
           skill.preferred_label_en?.toLowerCase().includes('basic') ||
           skill.preferred_label_en?.toLowerCase().includes('fundamental')),
        dxLevel: 'starter',
        importanceScore: 8,
        difficultyScore: 3
      },

      // DX Enabler (Level 2) 규칙
      {
        condition: (skill) => 
          skill.is_digital_skill &&
          (skill.preferred_label_en?.toLowerCase().includes('analysis') ||
           skill.preferred_label_en?.toLowerCase().includes('visualization') ||
           skill.preferred_label_en?.toLowerCase().includes('cleaning')),
        dxLevel: 'enabler',
        importanceScore: 7,
        difficultyScore: 5
      },

      // CDS (Level 3) 규칙
      {
        condition: (skill) => 
          skill.is_digital_skill &&
          (skill.preferred_label_en?.toLowerCase().includes('machine learning') ||
           skill.preferred_label_en?.toLowerCase().includes('artificial intelligence') ||
           skill.preferred_label_en?.toLowerCase().includes('deep learning') ||
           skill.preferred_label_en?.toLowerCase().includes('advanced')),
        dxLevel: 'cds',
        importanceScore: 9,
        difficultyScore: 8
      },

      // AX Level 1 규칙
      {
        condition: (skill) =>
          skill.is_digital_skill &&
          (skill.preferred_label_en?.toLowerCase().includes('data') ||
           skill.preferred_label_en?.toLowerCase().includes('analytics')),
        axLevel: 'lv1',
        importanceScore: 7,
        difficultyScore: 4
      },

      // AX Level 2 규칙
      {
        condition: (skill) =>
          skill.preferred_label_en?.toLowerCase().includes('machine learning') ||
          skill.preferred_label_en?.toLowerCase().includes('statistical'),
        axLevel: 'lv2',
        importanceScore: 8,
        difficultyScore: 6
      },

      // AX Level 3 규칙
      {
        condition: (skill) =>
          skill.preferred_label_en?.toLowerCase().includes('artificial intelligence') ||
          skill.preferred_label_en?.toLowerCase().includes('neural network') ||
          skill.preferred_label_en?.toLowerCase().includes('deep learning'),
        axLevel: 'lv3',
        importanceScore: 9,
        difficultyScore: 9
      }
    ];
  }

  /**
   * 전체 스킬 자동 매핑
   */
  async autoMapAllSkills(): Promise<{
    mapped: number;
    skipped: number;
    errors: number;
  }> {
    console.log('Starting auto-mapping process...');

    const rules = this.getMappingRules();
    let mapped = 0;
    let skipped = 0;
    let errors = 0;

    // 페이지네이션으로 모든 스킬 처리
    let offset = 0;
    const limit = 100;
    let hasMore = true;

    while (hasMore) {
      const skills = await this.skillsRepo.getAllSkills(offset, limit);

      if (skills.length === 0) {
        hasMore = false;
        break;
      }

      for (const skill of skills) {
        try {
          let skillMapped = false;

          for (const rule of rules) {
            if (rule.condition(skill)) {
              await this.mappingRepo.createMapping({
                skill_id: skill.id,
                dx_level: rule.dxLevel,
                ax_level: rule.axLevel,
                importance_score: rule.importanceScore,
                difficulty_score: rule.difficultyScore,
                created_by: 'auto-mapper'
              });

              skillMapped = true;
              mapped++;

              console.log(`✓ Mapped: ${skill.preferred_label_en} → ${rule.dxLevel || rule.axLevel}`);
              break; // 첫 번째 매칭 규칙만 적용
            }
          }

          if (!skillMapped) {
            skipped++;
          }

        } catch (error) {
          console.error(`✗ Error mapping skill ${skill.id}:`, error);
          errors++;
        }
      }

      offset += limit;
    }

    console.log(`\nAuto-mapping completed:`);
    console.log(`  Mapped: ${mapped}`);
    console.log(`  Skipped: ${skipped}`);
    console.log(`  Errors: ${errors}`);

    return { mapped, skipped, errors };
  }

  /**
   * 특정 스킬 매핑 제안
   */
  async suggestMapping(skillId: string): Promise<{
    dxLevel?: string;
    axLevel?: string;
    confidence: number;
    reason: string;
  } | null> {
    const skill = await this.skillsRepo.getSkillById(skillId);

    if (!skill) {
      return null;
    }

    const rules = this.getMappingRules();

    for (const rule of rules) {
      if (rule.condition(skill)) {
        return {
          dxLevel: rule.dxLevel,
          axLevel: rule.axLevel,
          confidence: 0.85,
          reason: this.explainMapping(skill, rule)
        };
      }
    }

    return {
      confidence: 0.0,
      reason: 'No matching rule found'
    };
  }

  /**
   * 매핑 설명 생성
   */
  private explainMapping(skill: any, rule: MappingRule): string {
    const reasons: string[] = [];

    if (skill.reusability_level === 'transversal') {
      reasons.push('Transversal skill (범용 스킬)');
    }

    if (skill.preferred_label_en?.toLowerCase().includes('basic')) {
      reasons.push('Contains "basic" keyword');
    }

    if (skill.preferred_label_en?.toLowerCase().includes('advanced')) {
      reasons.push('Contains "advanced" keyword');
    }

    return reasons.join(', ') || 'Pattern match';
  }
}
