// src/api/routes/mappings.ts

import { Router, Request, Response, NextFunction } from 'express';
import { MappingRepository } from '../../services/database/mappingRepository';
import { AutoMapper } from '../../services/mapping/autoMapper';

const router = Router();
const mappingRepo = new MappingRepository();
const autoMapper = new AutoMapper();

/**
 * GET /mappings/dx/:level
 * DX 레벨별 스킬 조회
 */
router.get('/dx/:level', async (req: Request, res: Response, next: NextFunction) => {
  try {
    const { level } = req.params;

    if (!['starter', 'enabler', 'cds'].includes(level)) {
      return res.status(400).json({
        error: 'Invalid level',
        message: 'Level must be: starter, enabler, or cds'
      });
    }

    const mappings = await mappingRepo.getMappingsByDXLevel(level);

    res.json({
      data: mappings,
      meta: {
        level,
        count: mappings.length
      }
    });
  } catch (error) {
    next(error);
  }
});

/**
 * GET /mappings/ax/:level
 * AX 레벨별 스킬 조회
 */
router.get('/ax/:level', async (req: Request, res: Response, next: NextFunction) => {
  try {
    const { level } = req.params;

    if (!['lv1', 'lv2', 'lv3'].includes(level)) {
      return res.status(400).json({
        error: 'Invalid level',
        message: 'Level must be: lv1, lv2, or lv3'
      });
    }

    const mappings = await mappingRepo.getMappingsByAXLevel(level);

    res.json({
      data: mappings,
      meta: {
        level,
        count: mappings.length
      }
    });
  } catch (error) {
    next(error);
  }
});

/**
 * POST /mappings/auto-map
 * 전체 스킬 자동 매핑 (Admin only)
 */
router.post('/auto-map', async (req: Request, res: Response, next: NextFunction) => {
  try {
    // Admin check

    const result = await autoMapper.autoMapAllSkills();

    res.json({
      data: result,
      message: 'Auto-mapping completed'
    });
  } catch (error) {
    next(error);
  }
});

/**
 * GET /mappings/suggest/:skillId
 * 스킬 매핑 제안
 */
router.get('/suggest/:skillId', async (req: Request, res: Response, next: NextFunction) => {
  try {
    const { skillId } = req.params;

    const suggestion = await autoMapper.suggestMapping(skillId);

    if (!suggestion) {
      return res.status(404).json({
        error: 'Skill not found'
      });
    }

    res.json({
      data: suggestion
    });
  } catch (error) {
    next(error);
  }
});

/**
 * POST /mappings
 * 수동 매핑 생성 (Admin only)
 */
router.post('/', async (req: Request, res: Response, next: NextFunction) => {
  try {
    const mappingData = req.body;

    const id = await mappingRepo.createMapping(mappingData);

    res.status(201).json({
      data: {
        id,
        message: 'Mapping created successfully'
      }
    });
  } catch (error) {
    next(error);
  }
});

/**
 * PUT /mappings/:id
 * 매핑 수정 (Admin only)
 */
router.put('/:id', async (req: Request, res: Response, next: NextFunction) => {
  try {
    const { id } = req.params;
    const updates = req.body;

    await mappingRepo.updateMapping(id, updates);

    res.json({
      message: 'Mapping updated successfully'
    });
  } catch (error) {
    next(error);
  }
});

export default router;
```

