### 핵심 로직

```typescript
// skillGapAnalyzer.ts

interface Skill {
  id: string;
  name: string;
  level: number; // 1-5
}

interface Occupation {
  id: string;
  name: string;
  requiredSkills: {
    skillId: string;
    importance: 'essential' | 'optional';
    minLevel: number;
  }[];
}

class SkillGapAnalyzer {
  /**
   * 스킬 갭 분석
   */
  analyzeGap(
    currentSkills: Skill[],
    targetOccupation: Occupation
  ): {
    matched: Skill[];
    gaps: { skillId: string; requiredLevel: number; gap: number }[];
    score: number;
  } {
    const currentSkillMap = new Map(
      currentSkills.map(s => [s.id, s.level])
    );

    const matched: Skill[] = [];
    const gaps: any[] = [];

    targetOccupation.requiredSkills.forEach(req => {
      const currentLevel = currentSkillMap.get(req.skillId) || 0;

      if (currentLevel >= req.minLevel) {
        matched.push(currentSkills.find(s => s.id === req.skillId)!);
      } else {
        gaps.push({
          skillId: req.skillId,
          requiredLevel: req.minLevel,
          currentLevel,
          gap: req.minLevel - currentLevel,
          importance: req.importance
        });
      }
    });

    // 스코어 계산 (0-100)
    const totalRequired = targetOccupation.requiredSkills.length;
    const score = Math.round((matched.length / totalRequired) * 100);

    return { matched, gaps, score };
  }

  /**
   * 학습 경로 생성
   */
  generateLearningPath(gaps: any[]): {
    phase: number;
    skills: string[];
    estimatedWeeks: number;
  }[] {
    // 우선순위: essential > gap 크기
    const sorted = gaps.sort((a, b) => {
      if (a.importance !== b.importance) {
        return a.importance === 'essential' ? -1 : 1;
      }
      return b.gap - a.gap;
    });

    // 3개월 단위로 그룹화
    const phases: any[] = [];
    const skillsPerPhase = 3;

    for (let i = 0; i < sorted.length; i += skillsPerPhase) {
      phases.push({
        phase: Math.floor(i / skillsPerPhase) + 1,
        skills: sorted.slice(i, i + skillsPerPhase).map(g => g.skillId),
        estimatedWeeks: 12
      });
    }

    return phases;
  }
}
```

