```python
# load_esco_to_neo4j.py

from neo4j import GraphDatabase
import csv

class ESCOLoader:
    def __init__(self, uri, user, password):
        self.driver = GraphDatabase.driver(uri, auth=(user, password))

    def close(self):
        self.driver.close()

    def load_skills(self, csv_file):
        """디지털 스킬 로드"""
        with self.driver.session() as session:
            with open(csv_file, 'r', encoding='utf-8') as f:
                reader = csv.DictReader(f)

                for row in reader:
                    session.write_transaction(
                        self._create_skill, row
                    )

    @staticmethod
    def _create_skill(tx, skill_data):
        query = """
        MERGE (s:Skill {uri: $uri})
        SET s.name = $name,
            s.description = $description,
            s.type = $type,
            s.digital = true
        """
        tx.run(query,
            uri=skill_data['conceptUri'],
            name=skill_data['preferredLabel'],
            description=skill_data.get('description', ''),
            type=skill_data.get('conceptType', 'skill')
        )

    def load_relationships(self, relationships_file):
        """스킬 관계 로드"""
        with self.driver.session() as session:
            with open(relationships_file, 'r') as f:
                reader = csv.DictReader(f)

                for row in reader:
                    session.write_transaction(
                        self._create_relationship, row
                    )

    @staticmethod
    def _create_relationship(tx, rel_data):
        query = """
        MATCH (s1:Skill {uri: $source})
        MATCH (s2:Skill {uri: $target})
        MERGE (s1)-[r:RELATED]->(s2)
        SET r.type = $rel_type
        """
        tx.run(query,
            source=rel_data['sourceUri'],
            target=rel_data['targetUri'],
            rel_type=rel_data.get('relationType', 'related')
        )

    def create_skill_groups(self):
        """스킬 그룹 생성 (DigComp 카테고리)"""
        categories = [
            'Information & Data Literacy',
            'Communication & Collaboration',
            'Digital Content Creation',
            'Safety',
            'Problem Solving'
        ]

        with self.driver.session() as session:
            for category in categories:
                session.write_transaction(
                    self._create_category, category
                )

    @staticmethod
    def _create_category(tx, category_name):
        query = """
        MERGE (c:SkillGroup {name: $name})
        SET c.type = 'DigComp'
        """
        tx.run(query, name=category_name)

# 실행
if __name__ == '__main__':
    loader = ESCOLoader("bolt://localhost:7687", "neo4j", "password")

    print("Loading skills...")
    loader.load_skills('digitalSkillsCollection.csv')

    print("Creating categories...")
    loader.create_skill_groups()

    print("Loading relationships...")
    loader.load_relationships('skillRelations.csv')

    loader.close()
    print("Done!")
```

### Cypher 쿼리 예제

```cypher
// 1. 모든 디지털 스킬 조회
MATCH (s:Skill {digital: true})
RETURN s.name, s.type
LIMIT 50;

// 2. Python과 관련된 스킬 찾기
MATCH (s:Skill {name: 'Python Programming'})-[:RELATED]-(related)
RETURN s.name, related.name;

// 3. 스킬 간 최단 경로
MATCH path = shortestPath(
  (s1:Skill {name: 'Python Programming'})-[*]-(s2:Skill {name: 'Machine Learning'})
)
RETURN path;

// 4. Data Scientist에게 필수인 스킬 Top 10
MATCH (o:Occupation {name: 'Data Scientist'})<-[:ESSENTIAL_FOR]-(s:Skill)
RETURN s.name, count(*) as importance
ORDER BY importance DESC
LIMIT 10;

// 5. 스킬 학습 경로 (prerequisite 따라가기)
MATCH path = (start:Skill {name: 'Basic Programming'})-[:PREREQUISITE_FOR*]->(end:Skill)
RETURN path
ORDER BY length(path) DESC
LIMIT 5;

// 6. 커뮤니티 감지 (유사 스킬 그룹)
CALL gds.louvain.stream('skillGraph')
YIELD nodeId, communityId
MATCH (s:Skill) WHERE id(s) = nodeId
RETURN communityId, collect(s.name) as skills
ORDER BY communityId;
```

