            {viewMode === 'tree' && (
              <CollapsibleTree
                filters={filters}
                onSelectSkill={setSelectedSkill}
              />
            )}
            {viewMode === 'sunburst' && (
              <SunburstChart
                filters={filters}
                onSelectSkill={setSelectedSkill}
              />
            )}
            {viewMode === 'force' && (
              <ForceGraph
                filters={filters}
                onSelectSkill={setSelectedSkill}
              />
            )}
          </div>
        </main>

        {/* 우측: 스킬 상세 정보 */}
        <aside className="details-panel">
          <SkillDetails skill={selectedSkill} />
        </aside>
      </div>
    </div>
  );
}

export default App;
