### 3.3 Sunburst Chart (원형 계층 차트)

```jsx
// src/components/SunburstChart.jsx

import React, { useEffect, useRef, useState } from 'react';
import * as d3 from 'd3';
import { getDigitalSkillsData } from '../data/escoData';

const SunburstChart = ({ filters, onSelectSkill }) => {
  const svgRef = useRef();
  const [data, setData] = useState(null);

  useEffect(() => {
    const skillsData = getDigitalSkillsData();
    setData(skillsData);
  }, [filters]);

  useEffect(() => {
    if (!data) return;

    const width = 800;
    const height = 800;
    const radius = Math.min(width, height) / 2;

    const svg = d3.select(svgRef.current);
    svg.selectAll('*').remove();

    const g = svg
      .attr('width', width)
      .attr('height', height)
      .append('g')
      .attr('transform', `translate(${width / 2},${height / 2})`);

    // Color scale
    const color = d3.scaleOrdinal()
      .domain(['Information & Data Literacy', 'Communication & Collaboration', 
               'Digital Content Creation', 'Safety & Security', 'Problem Solving'])
      .range(['#4CAF50', '#2196F3', '#FF9800', '#F44336', '#9C27B0']);

    // Hierarchy
    const root = d3.hierarchy(data)
      .sum(d => d.count || 1)
      .sort((a, b) => b.value - a.value);

    // Partition layout
    const partition = d3.partition()
      .size([2 * Math.PI, radius]);

    partition(root);

    // Arc generator
    const arc = d3.arc()
      .startAngle(d => d.x0)
      .endAngle(d => d.x1)
      .innerRadius(d => d.y0)
      .outerRadius(d => d.y1);

    // Draw arcs
    g.selectAll('path')
      .data(root.descendants())
      .enter()
      .append('path')
      .attr('d', arc)
      .style('fill', d => {
        if (d.depth === 0) return '#fff';
        if (d.depth === 1) return color(d.data.name);
        return d3.color(color(d.ancestors()[1].data.name)).brighter(d.depth * 0.3);
      })
      .style('stroke', '#fff')
      .style('stroke-width', 2)
      .style('cursor', 'pointer')
      .on('mouseover', function(event, d) {
        d3.select(this)
          .style('opacity', 0.8)
          .style('stroke-width', 3);

        // Tooltip
        showTooltip(event, d);
      })
      .on('mouseout', function() {
        d3.select(this)
          .style('opacity', 1)
          .style('stroke-width', 2);

        hideTooltip();
      })
      .on('click', (event, d) => {
        if (!d.children) {
          onSelectSkill(d.data);
        } else {
          zoom(d);
        }
      });

    // Labels (only for top levels)
    g.selectAll('text')
      .data(root.descendants().filter(d => d.depth === 1))
      .enter()
      .append('text')
      .attr('transform', d => {
        const angle = (d.x0 + d.x1) / 2;
        const radius = (d.y0 + d.y1) / 2;
        return `
          rotate(${angle * 180 / Math.PI - 90})
          translate(${radius},0)
          rotate(${angle > Math.PI ? 180 : 0})
        `;
      })
      .attr('dy', '0.35em')
      .attr('text-anchor', 'middle')
      .text(d => d.data.name)
      .style('font-size', '12px')
      .style('fill', '#333')
      .style('pointer-events', 'none');

    // Center label
    const centerLabel = g.append('text')
      .attr('text-anchor', 'middle')
      .style('font-size', '24px')
      .style('font-weight', 'bold')
      .style('fill', '#333');

    centerLabel.append('tspan')
      .attr('x', 0)
      .attr('dy', '-0.5em')
      .text('Digital Skills');

    centerLabel.append('tspan')
      .attr('x', 0)
      .attr('dy', '1.5em')
      .style('font-size', '36px')
      .style('fill', '#4CAF50')
      .text('1,201');

    // Zoom function
    function zoom(p) {
      root.each(d => d.target = {
        x0: Math.max(0, Math.min(1, (d.x0 - p.x0) / (p.x1 - p.x0))) * 2 * Math.PI,
        x1: Math.max(0, Math.min(1, (d.x1 - p.x0) / (p.x1 - p.x0))) * 2 * Math.PI,
        y0: Math.max(0, d.y0 - p.y0),
        y1: Math.max(0, d.y1 - p.y0)
      });

      const t = g.transition().duration(750);

      t.selectAll('path')
        .tween('data', d => {
          const i = d3.interpolate(d.current, d.target);
          return t => d.current = i(t);
        })
        .attrTween('d', d => () => arc(d.current));
    }

    // Tooltip
    function showTooltip(event, d) {
      const tooltip = d3.select('body').append('div')
        .attr('class', 'sunburst-tooltip')
        .style('position', 'absolute')
        .style('background', 'rgba(0,0,0,0.8)')
        .style('color', '#fff')
        .style('padding', '10px')
        .style('border-radius', '4px')
        .style('pointer-events', 'none')
        .style('left', (event.pageX + 10) + 'px')
        .style('top', (event.pageY - 10) + 'px');

      tooltip.html(`
        <strong>${d.data.name}</strong><br/>
        ${d.data.count ? `Skills: ${d.data.count}<br/>` : ''}
        ${d.data.level ? `Level: ${d.data.level}<br/>` : ''}
        Depth: ${d.depth}
      `);
    }

    function hideTooltip() {
      d3.selectAll('.sunburst-tooltip').remove();
    }

  }, [data, onSelectSkill]);

  return (
    <div className="sunburst-chart">
      <div className="sunburst-info">
        <p>💡 Hover to see details. Click to zoom in/out.</p>
      </div>
      <svg ref={svgRef}></svg>
    </div>
  );
};

export default SunburstChart;
