```jsx
// src/components/ForceGraph.jsx

import React, { useEffect, useRef, useState } from 'react';
import * as d3 from 'd3';
import { getDigitalSkillsNetwork } from '../data/escoData';

const ForceGraph = ({ filters, onSelectSkill }) => {
  const svgRef = useRef();
  const [data, setData] = useState(null);

  useEffect(() => {
    const networkData = getDigitalSkillsNetwork();
    setData(networkData);
  }, [filters]);

  useEffect(() => {
    if (!data) return;

    const width = 1200;
    const height = 800;

    const svg = d3.select(svgRef.current);
    svg.selectAll('*').remove();

    svg.attr('width', width).attr('height', height);

    // Force simulation
    const simulation = d3.forceSimulation(data.nodes)
      .force('link', d3.forceLink(data.links).id(d => d.id).distance(100))
      .force('charge', d3.forceManyBody().strength(-300))
      .force('center', d3.forceCenter(width / 2, height / 2))
      .force('collision', d3.forceCollide().radius(30));

    // Draw links
    const link = svg.append('g')
      .selectAll('line')
      .data(data.links)
      .enter()
      .append('line')
      .attr('stroke', '#999')
      .attr('stroke-opacity', 0.6)
      .attr('stroke-width', d => Math.sqrt(d.value || 1));

    // Draw nodes
    const node = svg.append('g')
      .selectAll('g')
      .data(data.nodes)
      .enter()
      .append('g')
      .call(d3.drag()
        .on('start', dragstarted)
        .on('drag', dragged)
        .on('end', dragended));

    node.append('circle')
      .attr('r', d => getNodeSize(d))
      .attr('fill', d => getNodeColor(d))
      .attr('stroke', '#fff')
      .attr('stroke-width', 2)
      .style('cursor', 'pointer')
      .on('click', (event, d) => {
        if (d.type === 'skill') {
          onSelectSkill(d);
        }
      });

    node.append('text')
      .text(d => d.name)
      .attr('x', 12)
      .attr('y', 4)
      .style('font-size', '11px')
      .style('pointer-events', 'none');

    // Simulation tick
    simulation.on('tick', () => {
      link
        .attr('x1', d => d.source.x)
        .attr('y1', d => d.source.y)
        .attr('x2', d => d.target.x)
        .attr('y2', d => d.target.y);

      node.attr('transform', d => `translate(${d.x},${d.y})`);
    });

    // Drag functions
    function dragstarted(event, d) {
      if (!event.active) simulation.alphaTarget(0.3).restart();
      d.fx = d.x;
      d.fy = d.y;
    }

    function dragged(event, d) {
      d.fx = event.x;
      d.fy = event.y;
    }

    function dragended(event, d) {
      if (!event.active) simulation.alphaTarget(0);
      d.fx = null;
      d.fy = null;
    }

    function getNodeSize(d) {
      if (d.type === 'category') return 20;
      if (d.type === 'group') return 12;
      return 8;
    }

    function getNodeColor(d) {
      const colors = {
        'category': '#4CAF50',
        'group': '#2196F3',
        'skill': '#FF9800'
      };
      return colors[d.type] || '#999';
    }

  }, [data, onSelectSkill]);

  return (
    <div className="force-graph">
      <div className="force-info">
        <p>💡 Drag nodes to explore. Click skills for details.</p>
      </div>
      <svg ref={svgRef}></svg>
    </div>
  );
};

export default ForceGraph;
