### 3.2 Collapsible Tree (접을 수 있는 트리)

```jsx
// src/components/CollapsibleTree.jsx

import React, { useEffect, useRef, useState } from 'react';
import * as d3 from 'd3';
import { getDigitalSkillsData } from '../data/escoData';

const CollapsibleTree = ({ filters, onSelectSkill }) => {
  const svgRef = useRef();
  const [data, setData] = useState(null);

  useEffect(() => {
    // 데이터 로드 및 필터링
    const skillsData = getDigitalSkillsData();
    const filtered = applyFilters(skillsData, filters);
    setData(filtered);
  }, [filters]);

  useEffect(() => {
    if (!data) return;

    // SVG 초기화
    const svg = d3.select(svgRef.current);
    svg.selectAll('*').remove();

    const width = 1200;
    const height = 800;
    const margin = { top: 20, right: 120, bottom: 20, left: 120 };

    const g = svg
      .attr('width', width)
      .attr('height', height)
      .append('g')
      .attr('transform', `translate(${margin.left},${margin.top})`);

    // D3 Tree Layout
    const treeLayout = d3.tree()
      .size([height - margin.top - margin.bottom, width - margin.left - margin.right]);

    // Hierarchy 생성
    const root = d3.hierarchy(data);

    // 초기 상태: 2 레벨까지만 펼침
    root.descendants().forEach(d => {
      d._children = d.children;
      if (d.depth > 1) {
        d.children = null;
      }
    });

    update(root);

    function update(source) {
      // 트리 레이아웃 적용
      const treeData = treeLayout(root);
      const nodes = treeData.descendants();
      const links = treeData.links();

      // 노드 간격 조정
      nodes.forEach(d => {
        d.y = d.depth * 180;
      });

      // 링크 그리기 (곡선)
      const link = g.selectAll('.link')
        .data(links, d => d.target.id || (d.target.id = ++i));

      link.exit().transition().duration(500)
        .attr('opacity', 0)
        .remove();

      const linkEnter = link.enter()
        .append('path')
        .attr('class', 'link')
        .attr('d', d => {
          const o = { x: source.x0 || source.x, y: source.y0 || source.y };
          return diagonal(o, o);
        })
        .attr('fill', 'none')
        .attr('stroke', '#ccc')
        .attr('stroke-width', 2);

      const linkUpdate = linkEnter.merge(link);

      linkUpdate.transition().duration(500)
        .attr('d', d => diagonal(d.source, d.target))
        .attr('opacity', 1);

      // 노드 그리기
      const node = g.selectAll('.node')
        .data(nodes, d => d.id || (d.id = ++i));

      node.exit().transition().duration(500)
        .attr('opacity', 0)
        .remove();

      const nodeEnter = node.enter()
        .append('g')
        .attr('class', 'node')
        .attr('transform', d => `translate(${source.y0 || source.y},${source.x0 || source.x})`)
        .on('click', click);

      // 노드 원
      nodeEnter.append('circle')
        .attr('r', 8)
        .style('fill', d => getNodeColor(d))
        .style('stroke', '#fff')
        .style('stroke-width', 2)
        .style('cursor', 'pointer');

      // 노드 레이블
      nodeEnter.append('text')
        .attr('dy', '.35em')
        .attr('x', d => d.children || d._children ? -13 : 13)
        .attr('text-anchor', d => d.children || d._children ? 'end' : 'start')
        .text(d => {
          const name = d.data.name;
          const count = d.data.count ? ` (${d.data.count})` : '';
          return name + count;
        })
        .style('font-size', d => d.depth === 0 ? '16px' : '12px')
        .style('font-weight', d => d.depth === 0 ? 'bold' : 'normal')
        .style('fill', '#333');

      // DX Level 뱃지
      nodeEnter.filter(d => d.data.level)
        .append('rect')
        .attr('x', 15)
        .attr('y', -10)
        .attr('width', 50)
        .attr('height', 18)
        .attr('rx', 4)
        .style('fill', d => getLevelColor(d.data.level))
        .style('opacity', 0.8);

      nodeEnter.filter(d => d.data.level)
        .append('text')
        .attr('x', 40)
        .attr('y', 2)
        .attr('text-anchor', 'middle')
        .text(d => d.data.level.toUpperCase())
        .style('font-size', '10px')
        .style('fill', '#fff')
        .style('font-weight', 'bold');

      const nodeUpdate = nodeEnter.merge(node);

      nodeUpdate.transition().duration(500)
        .attr('transform', d => `translate(${d.y},${d.x})`)
        .attr('opacity', 1);

      nodeUpdate.select('circle')
        .style('fill', d => getNodeColor(d));

      // 노드 저장 (애니메이션용)
      nodes.forEach(d => {
        d.x0 = d.x;
        d.y0 = d.y;
      });

      // 클릭 핸들러: 펼치기/접기
      function click(event, d) {
        if (d.children) {
          d._children = d.children;
          d.children = null;
        } else {
          d.children = d._children;
          d._children = null;
        }

        // 스킬 선택 (리프 노드인 경우)
        if (!d._children && !d.children) {
          onSelectSkill(d.data);
        }

        update(d);
      }
    }

    // Diagonal path generator
    function diagonal(s, d) {
      return `M ${s.y} ${s.x}
              C ${(s.y + d.y) / 2} ${s.x},
                ${(s.y + d.y) / 2} ${d.x},
                ${d.y} ${d.x}`;
    }

    let i = 0;

  }, [data, onSelectSkill]);

  // 노드 색상
  const getNodeColor = (d) => {
    if (d.children || d._children) {
      return d.depth === 0 ? '#4CAF50' : '#2196F3';
    }
    // 리프 노드 (스킬)
    return '#FF9800';
  };

  // DX Level 색상
  const getLevelColor = (level) => {
    const colors = {
      'starter': '#4CAF50',
      'enabler': '#2196F3',
      'cds': '#9C27B0'
    };
    return colors[level] || '#999';
  };

  // 필터 적용
  const applyFilters = (data, filters) => {
    let filtered = JSON.parse(JSON.stringify(data)); // Deep clone

    if (filters.dxLevel !== 'all') {
      filtered = filterByLevel(filtered, filters.dxLevel);
    }

    if (filters.searchTerm) {
      filtered = filterBySearch(filtered, filters.searchTerm);
    }

    return filtered;
  };

  const filterByLevel = (node, targetLevel) => {
    if (!node.children) {
      return node.level === targetLevel ? node : null;
    }

    const filteredChildren = node.children
      .map(child => filterByLevel(child, targetLevel))
      .filter(child => child !== null);

    if (filteredChildren.length === 0) return null;

    return { ...node, children: filteredChildren };
  };

  const filterBySearch = (node, searchTerm) => {
    const term = searchTerm.toLowerCase();

    if (!node.children) {
      return node.name.toLowerCase().includes(term) ? node : null;
    }

    const filteredChildren = node.children
      .map(child => filterBySearch(child, term))
      .filter(child => child !== null);

    if (filteredChildren.length === 0 && !node.name.toLowerCase().includes(term)) {
      return null;
    }

    return { ...node, children: filteredChildren };
  };

  return (
    <div className="collapsible-tree">
      <div className="tree-info">
        <p>💡 Click nodes to expand/collapse. Click skills to see details.</p>
      </div>
      <svg ref={svgRef}></svg>
    </div>
  );
};

export default CollapsibleTree;
