```javascript
// src/utils/csvParser.js

import Papa from 'papaparse';

export const parseESCOCSV = (csvFile) => {
  return new Promise((resolve, reject) => {
    Papa.parse(csvFile, {
      header: true,
      dynamicTyping: true,
      complete: (results) => {
        const skills = results.data.map(row => ({
          uri: row.conceptUri,
          name: row.preferredLabel,
          description: row.description,
          type: row.conceptType,
          reusability: row.skillReuseLevel
        }));
        resolve(skills);
      },
      error: (error) => reject(error)
    });
  });
};

// 사용
import { parseESCOCSV } from './utils/csvParser';

const file = document.getElementById('file-input').files[0];
const skills = await parseESCOCSV(file);
