import React, { useEffect, useRef } from 'react';
import * as d3 from 'd3';
import './CollapsibleTree.css';

const CollapsibleTree = ({ data, onSelectSkill }) => {
  const svgRef = useRef();
  const containerRef = useRef();

  useEffect(() => {
    if (!data) return;

    // Clear previous content
    d3.select(svgRef.current).selectAll('*').remove();

    const width = 1400;
    const height = 1000;
    const margin = { top: 20, right: 200, bottom: 20, left: 200 };

    const svg = d3.select(svgRef.current)
      .attr('width', width)
      .attr('height', height);

    const g = svg.append('g')
      .attr('transform', `translate(${margin.left},${margin.top})`);

    // Create tree layout
    const treeLayout = d3.tree()
      .size([height - margin.top - margin.bottom, width - margin.left - margin.right]);

    // Create hierarchy
    const root = d3.hierarchy(data);

    // Initially collapse all nodes below depth 2
    root.descendants().forEach(d => {
      d._children = d.children;
      if (d.depth > 1) {
        d.children = null;
      }
    });

    let i = 0; // for unique IDs
    const duration = 500;

    // Update function
    function update(source) {
      // Compute the new tree layout
      const treeData = treeLayout(root);
      const nodes = treeData.descendants();
      const links = treeData.links();

      // Normalize for fixed-depth
      nodes.forEach(d => {
        d.y = d.depth * 220;
      });

      // ****************** Nodes section ***************************

      // Update the nodes...
      const node = g.selectAll('g.node')
        .data(nodes, d => d.id || (d.id = ++i));

      // Enter any new nodes at the parent's previous position
      const nodeEnter = node.enter().append('g')
        .attr('class', 'node')
        .attr('transform', d => `translate(${source.y0 || source.y},${source.x0 || source.x})`)
        .on('click', click);

      // Add Circle for the nodes
      nodeEnter.append('circle')
        .attr('class', 'node-circle')
        .attr('r', 1e-6)
        .style('fill', d => d._children ? getLevelColor(d.data.level) : '#fff')
        .style('stroke', d => getNodeStroke(d))
        .style('stroke-width', d => d.data.category === 'skill' ? 3 : 2);

      // Add count badge for nodes with children
      nodeEnter.filter(d => d.data.count)
        .append('circle')
        .attr('class', 'count-badge')
        .attr('cx', 15)
        .attr('cy', -10)
        .attr('r', 12)
        .style('fill', '#FF9800')
        .style('opacity', 0);

      nodeEnter.filter(d => d.data.count)
        .append('text')
        .attr('class', 'count-text')
        .attr('x', 15)
        .attr('y', -6)
        .attr('text-anchor', 'middle')
        .style('fill', '#fff')
        .style('font-size', '10px')
        .style('font-weight', 'bold')
        .style('opacity', 0)
        .text(d => d.data.count);

      // Add labels for the nodes
      nodeEnter.append('text')
        .attr('class', 'node-label')
        .attr('dy', '.35em')
        .attr('x', d => d.children || d._children ? -13 : 13)
        .attr('text-anchor', d => d.children || d._children ? 'end' : 'start')
        .text(d => {
          const name = d.data.name;
          // Truncate long names
          return name.length > 50 ? name.substring(0, 47) + '...' : name;
        })
        .style('fill-opacity', 1e-6)
        .style('font-size', d => {
          if (d.depth === 0) return '18px';
          if (d.depth === 1) return '14px';
          if (d.depth === 2) return '12px';
          return '11px';
        })
        .style('font-weight', d => d.depth <= 1 ? 'bold' : 'normal');

      // Add level badge for skill nodes
      const skillNodes = nodeEnter.filter(d => d.data.level);

      skillNodes.append('rect')
        .attr('class', 'level-badge')
        .attr('x', 15)
        .attr('y', -8)
        .attr('width', 50)
        .attr('height', 16)
        .attr('rx', 8)
        .style('fill', d => getLevelColor(d.data.level))
        .style('opacity', 0);

      skillNodes.append('text')
        .attr('class', 'level-text')
        .attr('x', 40)
        .attr('y', 2)
        .attr('text-anchor', 'middle')
        .style('fill', '#fff')
        .style('font-size', '9px')
        .style('font-weight', 'bold')
        .style('opacity', 0)
        .text(d => d.data.level ? d.data.level.toUpperCase() : '');

      // Add popularity indicator
      skillNodes.filter(d => d.data.popularity)
        .append('rect')
        .attr('class', 'popularity-bar')
        .attr('x', 70)
        .attr('y', -6)
        .attr('width', d => (d.data.popularity || 0) * 0.4)
        .attr('height', 12)
        .attr('rx', 2)
        .style('fill', d => getPopularityColor(d.data.popularity))
        .style('opacity', 0);

      // UPDATE
      const nodeUpdate = nodeEnter.merge(node);

      // Transition to the proper position for the node
      nodeUpdate.transition()
        .duration(duration)
        .attr('transform', d => `translate(${d.y},${d.x})`);

      // Update the node attributes and style
      nodeUpdate.select('circle.node-circle')
        .attr('r', d => {
          if (d.depth === 0) return 12;
          if (d.depth === 1) return 10;
          if (d.depth === 2) return 8;
          return 6;
        })
        .style('fill', d => {
          if (d._children) return getLevelColor(d.data.level);
          if (d.data.category === 'skill') return '#fff';
