import React from 'react';
import './SkillDetails.css';

const SkillDetails = ({ skill }) => {
  if (!skill) {
    return (
      <div className="skill-details empty">
        <div className="empty-state">
          <div className="empty-icon">📊</div>
          <h3>Select a Skill</h3>
          <p>Click on any skill node in the tree to see detailed information</p>
          <div className="empty-hints">
            <h4>Tips:</h4>
            <ul>
              <li>Click nodes to expand/collapse</li>
              <li>Use zoom controls to navigate</li>
              <li>Click skill nodes (leaves) for details</li>
            </ul>
          </div>
        </div>
      </div>
    );
  }

  const getLevelInfo = (level) => {
    const info = {
      'starter': {
        color: '#4CAF50',
        description: 'Basic understanding and fundamental knowledge',
        requirements: 'No prerequisites'
      },
      'enabler': {
        color: '#2196F3',
        description: 'Practical application and intermediate proficiency',
        requirements: 'Basic knowledge required'
      },
      'cds': {
        color: '#9C27B0',
        description: 'Advanced expertise and specialized skills',
        requirements: 'Strong foundation required'
      }
    };
    return info[level] || info['starter'];
  };

  const levelInfo = getLevelInfo(skill.level);

  return (
    <div className="skill-details">
      <div className="skill-header">
        <h2>{skill.name}</h2>
        <span 
          className={`skill-level-badge ${skill.level}`}
          style={{ backgroundColor: levelInfo.color }}
        >
          {skill.level?.toUpperCase()}
        </span>
      </div>

      {skill.description && (
        <div className="skill-section">
          <h3>📝 Description</h3>
          <p>{skill.description}</p>
        </div>
      )}

      <div className="skill-section">
        <h3>📊 Level Information</h3>
        <div className="level-info">
          <p className="level-description">{levelInfo.description}</p>
          <div className="level-requirement">
            <strong>Requirements:</strong> {levelInfo.requirements}
          </div>
        </div>
      </div>

      {skill.popularity && (
        <div className="skill-section">
          <h3>🔥 Popularity</h3>
          <div className="popularity-container">
            <div className="popularity-bar-container">
              <div 
                className="popularity-bar-fill"
                style={{ 
                  width: `${skill.popularity}%`,
                  backgroundColor: getPopularityColor(skill.popularity)
                }}
              >
                <span className="popularity-text">{skill.popularity}%</span>
              </div>
            </div>
            <p className="popularity-note">
              Found in {skill.popularity}% of job postings
            </p>
          </div>
        </div>
      )}

      {skill.relatedSkills && skill.relatedSkills.length > 0 && (
        <div className="skill-section">
          <h3>🔗 Related Skills</h3>
          <div className="related-skills-list">
            {skill.relatedSkills.map((relatedSkill, index) => (
              <span key={index} className="related-skill-tag">
                {relatedSkill}
              </span>
            ))}
          </div>
        </div>
      )}

      {skill.industries && skill.industries.length > 0 && (
        <div className="skill-section">
          <h3>🏢 Industries</h3>
          <div className="industries-list">
            {skill.industries.map((industry, index) => (
              <span key={index} className="industry-tag">
                {industry}
              </span>
            ))}
          </div>
        </div>
      )}

      {skill.uri && (
        <div className="skill-section">
          <h3>🔗 ESCO URI</h3>
          <a 
            href={skill.uri} 
            target="_blank" 
            rel="noopener noreferrer"
            className="esco-link"
          >
            View on ESCO Portal →
          </a>
        </div>
      )}

      <div className="skill-actions">
        <button className="action-button primary">
          <span className="button-icon">✅</span>
          Add to My Skills
        </button>
        <button className="action-button secondary">
          <span className="button-icon">📚</span>
          Find Learning Resources
        </button>
        <button className="action-button secondary">
          <span className="button-icon">💼</span>
          View Job Opportunities
        </button>
      </div>

      <div className="skill-metadata">
        <div className="metadata-item">
          <span className="metadata-label">Category:</span>
          <span className="metadata-value">{skill.category || 'Digital Skill'}</span>
        </div>
        <div className="metadata-item">
          <span className="metadata-label">Level:</span>
          <span className="metadata-value">{skill.level?.toUpperCase()}</span>
        </div>
      </div>
    </div>
  );
};

function getPopularityColor(popularity) {
  if (popularity >= 90) return '#4CAF50';
  if (popularity >= 75) return '#8BC34A';
  if (popularity >= 60) return '#FFC107';
  return '#FF9800';
}

export default SkillDetails;

