.stat-card:hover {
  transform: translateY(-4px);
  box-shadow: 0 6px 16px rgba(0, 0, 0, 0.1);
}

.stat-card.starter {
  border-color: #4CAF50;
  background: linear-gradient(135deg, #e8f5e9 0%, #f1f8f2 100%);
}

.stat-card.enabler {
  border-color: #2196F3;
  background: linear-gradient(135deg, #e3f2fd 0%, #f0f7ff 100%);
}

.stat-card.cds {
  border-color: #9C27B0;
  background: linear-gradient(135deg, #f3e5f5 0%, #f8f0fa 100%);
}

.stat-icon {
  font-size: 2rem;
}

.stat-value {
  font-size: 2rem;
  font-weight: 700;
  color: #333;
  line-height: 1;
}

.stat-label {
  font-size: 0.875rem;
  color: #666;
  margin-top: 0.25rem;
}

/* Container */
.app-container {
  flex: 1;
  display: grid;
  grid-template-columns: 280px 1fr 350px;
  gap: 1.5rem;
  padding: 1.5rem 2rem;
  max-width: 1920px;
  margin: 0 auto;
  width: 100%;
}

/* Info Panel */
.info-panel {
  display: flex;
  flex-direction: column;
  gap: 1rem;
  overflow-y: auto;
  max-height: calc(100vh - 280px);
}

.info-card {
  background: white;
  border-radius: 12px;
  padding: 1.5rem;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.08);
}

.info-card h3 {
  font-size: 1rem;
  margin-bottom: 1rem;
  color: #333;
