  align-items: center;
  gap: 0.5rem;
}

.info-card ul {
  list-style: none;
  padding: 0;
  margin: 0;
}

.info-card li {
  margin-bottom: 0.75rem;
  font-size: 0.875rem;
  line-height: 1.5;
  color: #666;
}

.info-card li strong {
  color: #333;
  font-weight: 600;
}

.info-card p {
  font-size: 0.875rem;
  line-height: 1.6;
  color: #666;
  margin-bottom: 1rem;
}

.info-card p:last-child {
  margin-bottom: 0;
}

.info-version {
  background: #f8f9fa;
  padding: 0.75rem;
  border-radius: 6px;
  font-size: 0.8rem;
  line-height: 1.8;
}

.info-version strong {
  color: #2196F3;
}

/* Level Info */
.level-info-item {
  margin-bottom: 1rem;
}

.level-info-item:last-child {
  margin-bottom: 0;
}

.level-badge {
  display: inline-block;
  padding: 4px 12px;
  border-radius: 12px;
  font-size: 0.75rem;
  font-weight: 700;
  color: white;
  margin-bottom: 0.5rem;
}

.level-badge.starter {
  background: #4CAF50;
}

.level-badge.enabler {
  background: #2196F3;
}

.level-badge.cds {
  background: #9C27B0;
}

.level-info-item p {
  margin: 0;
  font-size: 0.8rem;
  line-height: 1.4;
}

/* Resources */
.resource-link {
  display: block;
  padding: 0.75rem;
  margin-bottom: 0.5rem;
  background: #f8f9fa;
  color: #2196F3;
  text-decoration: none;
  border-radius: 6px;
  font-size: 0.875rem;
  font-weight: 600;
  transition: all 0.2s;
}

.resource-link:hover {
  background: #e3f2fd;
  transform: translateX(4px);
}

.resource-link:last-child {
  margin-bottom: 0;
}

/* Tree Area */
.tree-area {
  background: white;
  border-radius: 12px;
  padding: 1.5rem;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.08);
  display: flex;
  flex-direction: column;
}

.tree-header {
  margin-bottom: 1rem;
  padding-bottom: 1rem;
  border-bottom: 2px solid #f0f0f0;
}

.tree-header h2 {
  font-size: 1.5rem;
  color: #333;
  margin-bottom: 0.25rem;
}

.tree-header p {
  font-size: 0.875rem;
  color: #999;
  margin: 0;
}

.tree-container {
  flex: 1;
  min-height: 600px;
  position: relative;
}

/* Details Panel */
.details-panel {
  overflow-y: auto;
  max-height: calc(100vh - 280px);
}

/* Footer */
.app-footer {
  background: #333;
  color: white;
  padding: 1.5rem 2rem;
  text-align: center;
  font-size: 0.875rem;
  margin-top: auto;
}

.app-footer p {
  margin: 0;
  opacity: 0.9;
}

/* Scrollbar Styling */
.info-panel::-webkit-scrollbar,
.details-panel::-webkit-scrollbar {
  width: 8px;
}

.info-panel::-webkit-scrollbar-track,
.details-panel::-webkit-scrollbar-track {
  background: #f0f0f0;
  border-radius: 4px;
}

.info-panel::-webkit-scrollbar-thumb,
.details-panel::-webkit-scrollbar-thumb {
  background: #ccc;
  border-radius: 4px;
}

.info-panel::-webkit-scrollbar-thumb:hover,
.details-panel::-webkit-scrollbar-thumb:hover {
  background: #999;
}

/* Responsive Design */
@media (max-width: 1400px) {
  .app-container {
    grid-template-columns: 240px 1fr 320px;
  }
}

@media (max-width: 1200px) {
  .app-container {
    grid-template-columns: 1fr;
    grid-template-rows: auto;
  }

  .info-panel {
    max-height: none;
    flex-direction: row;
    overflow-x: auto;
  }

  .info-card {
    min-width: 250px;
  }

  .details-panel {
    max-height: 500px;
  }

  .stats-bar {
    overflow-x: scroll;
  }

