    font-size: 0.875rem;
  }

  .stats-toggle {
    position: static;
    margin-top: 1rem;
    width: 100%;
  }

  .stats-bar {
    padding: 1rem;
    gap: 0.75rem;
  }

  .app-container {
    padding: 1rem;
    gap: 1rem;
  }

  .tree-container {
    min-height: 400px;
  }
}

/* Loading Animation */
@keyframes pulse {
  0%, 100% {
    opacity: 1;
  }
  50% {
    opacity: 0.5;
  }
}

